struct Info {
	Info() : sum(0), cnt(0) {};
	Info(ll sum, ll cnt) : sum(sum), cnt(cnt) {};

	// 要维护的值
	ll sum, cnt;
	void apply(const Info& v) {
		// 如何单点修改
		sum += v.sum;
		cnt += v.cnt;
	}
};
Info operator+(const Info& a, const Info& b) {
	Info c;
	c.sum = a.sum + b.sum;
	c.cnt = a.cnt + b.cnt;
	return c;
}

void solve(int CASE)
{
	ll n, m, f; cin >> n >> m >> f;
	var s = vector<pll>(m + 1);
	ll valmx = 0;
	fa(i, 1, m)cin >> s[i].px >> s[i].py, valmx = max(valmx, s[i].py);
	sort(all1(s));
	ll mid = n / 2;
	var segmn = SegmentTree<Info>(valmx + 1);
	var segmx = SegmentTree<Info>(valmx + 1);
	fa(i, 1, mid)segmn.modify(s[i].py, { s[i].py, 1 });
	fa(i, mid + 2, m)segmx.modify(s[i].py, { s[i].py, 1 });
	ll ans = -1;
	fa(i, mid + 1, m - mid) {
		ll mnval = segmn.query2(mid);
		var mnres = segmn.query(mid);
		ll mnsum = mnres.sum - (mnres.cnt - mid) * mnval;

		ll mxval = segmx.query2(mid);
		var mxres = segmx.query(mid);
		ll mxsum = mxres.sum - (mxres.cnt - mid) * mxval;

		if (mxsum + mnsum + s[i].py <= f)ans = s[i].px;

		segmn.modify(s[i].py, { s[i].py, 1 });
		segmx.modify(s[i + 1].py, { -s[i + 1].py, -1 });
	}
	cout << ans << endl;
	return;
}
